import React from "react";
import MapComponent from "./MapComponent";
import BusTrendChart from "./BusTrendChart";

function App() {
  return (
    <div>
      <h1 style={{ textAlign: "center", margin: "20px 0" }}>NYC Ghost Bus Detector</h1>
      <MapComponent />
      <BusTrendChart />
    </div>
  );
}

export default App;
